 1	import React, { Dispatch, FC, SetStateAction } from 'react';
 2	
 3	import { V1beta1DataVolume } from '@kubevirt-ui/kubevirt-api/containerized-data-importer/models';
 4	import { IoK8sApiCoreV1PersistentVolumeClaim } from '@kubevirt-ui/kubevirt-api/kubernetes/models';
 5	import { V1beta1VirtualMachineSnapshot } from '@kubevirt-ui/kubevirt-api/kubevirt';
 6	import Loading from '@kubevirt-utils/components/Loading/Loading';
 7	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 8	import { getName } from '@kubevirt-utils/resources/shared';
 9	import { isEmpty } from '@kubevirt-utils/utils/utils';
10	import { Bullseye, StackItem } from '@patternfly/react-core';
11	
12	import { findPVCOwner } from '../utils/helpers';
13	
14	import DeleteResourceCheckbox from './DeleteResourceCheckbox';
15	
16	type DeleteOwnedResourcesMessageProps = {
17	  dataVolumes: V1beta1DataVolume[];
18	  loaded: boolean;
19	  pvcs: IoK8sApiCoreV1PersistentVolumeClaim[];
20	  setSnapshotsToSave: Dispatch<SetStateAction<V1beta1VirtualMachineSnapshot[]>>;
21	  setVolumesToSave: Dispatch<
22	    SetStateAction<(IoK8sApiCoreV1PersistentVolumeClaim | V1beta1DataVolume)[]>
23	  >;
24	  snapshots: V1beta1VirtualMachineSnapshot[];
25	  snapshotsToSave: V1beta1VirtualMachineSnapshot[];
26	  volumesToSave: (IoK8sApiCoreV1PersistentVolumeClaim | V1beta1DataVolume)[];
27	};
28	
29	const DeleteOwnedResourcesMessage: FC<DeleteOwnedResourcesMessageProps> = ({
30	  dataVolumes,
31	  loaded,
32	  pvcs,
33	  setSnapshotsToSave,
34	  setVolumesToSave,
35	  snapshots,
36	  snapshotsToSave,
37	  volumesToSave,
38	}) => {
39	  const { t } = useKubevirtTranslation();
40	
41	  if (!loaded) {
42	    return (
43	      <Bullseye>
44	        <Loading />
45	      </Bullseye>
46	    );
47	  }
48	
49	  const pvcsWithNoDataVolumes = pvcs?.filter((pvc) => !findPVCOwner(pvc, dataVolumes)) || [];
50	
51	  const diskCount = dataVolumes?.length + pvcsWithNoDataVolumes?.length || 0;
52	
53	  return (
54	    <>
55	      {!!diskCount && (
56	        <StackItem>
57	          {t(
58	            'The following resources will be deleted along with this VirtualMachine. Unchecked items will not be deleted.',
59	          )}
60	        </StackItem>
61	      )}
62	
63	      {[...(dataVolumes || []), ...pvcsWithNoDataVolumes].map((resource) => (
64	        <DeleteResourceCheckbox
65	          key={`${resource.kind}-${getName(resource)}`}
66	          resource={resource}
67	          resourcesToSave={volumesToSave}
68	          setResourcesToSave={setVolumesToSave}
69	        />
70	      ))}
71	
72	      {!isEmpty(snapshots) &&
73	        snapshots.map((snapshot) => (
74	          <DeleteResourceCheckbox
75	            key={`${snapshot.kind}-${getName(snapshot)}`}
76	            resource={snapshot}
77	            resourcesToSave={snapshotsToSave}
78	            setResourcesToSave={setSnapshotsToSave}
79	          />
80	        ))}
81	    </>
82	  );
83	};
84	
85	export default DeleteOwnedResourcesMessage;

